101: func (s groupVersionKinds) Less(i, j int) bool {
102: 	if s[i].Group == s[j].Group {
103: 		if s[i].Version == s[j].Version {
104: 			return s[i].Kind < s[j].Kind
105: 		}
106: 		return s[i].Version < s[j].Version
107: 	}
108: 	return s[i].Group < s[j].Group
