128: func gvkConvert(gvk schema.GroupVersionKind) v1.GroupVersionKind {
129: 	return v1.GroupVersionKind{
130: 		Group:   gvk.Group,
131: 		Version: gvk.Version,
132: 		Kind:    gvk.Kind,
133: 	}
134: }
