149: func typeName(t reflect.Type) string {
150: 	path := t.PkgPath()
151: 	if strings.Contains(path, "/vendor/") {
152: 		path = path[strings.Index(path, "/vendor/")+len("/vendor/"):]
153: 	}
154: 	return fmt.Sprintf("%s.%s", path, t.Name())
155: }
